function dedupeSorted(a) {
  if (a.length === 0) return 0;
  let w = 1;
  for (let i = 1; i < a.length; i++) {
    if (a[i] !== a[w - 1]) {
      a[w] = a[i];
      w++;
    }
  }
  a.length = w;
  return w;
}

