function mergeSorted(A, B) {
  let i = 0, j = 0;
  const out = [];
  while (i < A.length && j < B.length) {
    if (A[i] <= B[j]) { out.push(A[i]); i++; }
    else { out.push(B[j]); j++; }
  }
  while (i < A.length) { out.push(A[i]); i++; }
  while (j < B.length) { out.push(B[j]); j++; }
  return out;
}

